To serve a webpage template based on the assigned template type, you can use a template engine like EJS or Handlebars. First, install the template engine using NPM:

```
npm install ejs
```

Then, you can modify the code like this:

```
const express = require('express');
const app = express();
const ejs = require('ejs'); // Require the EJS module

// Define an array of IP addresses and their assigned template types
const ipTemplates = [
  { ip: '192.168.1.100', template: 'template1' },
  { ip: '192.168.1.101', template: 'template2' },
  { ip: '192.168.1.102', template: 'template3' }
];

// Define a function that gets the template type for a given IP address
function getTemplateType(ip) {
  const ipTemplate = ipTemplates.find(ipTemplate => ipTemplate.ip === ip);
  return ipTemplate ? ipTemplate.template : null;
}

// Set up a route that serves a webpage template based on the assigned template type
app.get('/', (req, res) => {
  const ip = req.ip; // Get the IP address of the request
  const templateType = getTemplateType(ip); // Lookup the template type for the IP address
  if (templateType) {
    const templateData = { templateType }; // Create an object with the template data
    res.render(`${templateType}.ejs`, templateData); // Render the template using EJS
  } else {
    res.send('Template not found');
  }
});

// Set up SSE for each template type
app.get('/sse/:templateType', (req, res) => {
  const templateType = req.params.templateType;
  res.set('Content-Type', 'text/event-stream');
  res.set('Cache-Control', 'no-cache');

  const intervalId = setInterval(() => {
    res.write(`data: This is an SSE message for ${templateType}\n\n`);
  }, 1000);

  req.on('close', () => {
    clearInterval(intervalId);
  });
});

// Start the server
app.listen(3000, () => {
  console.log('Server started on port 3000');
});
```

This code sets up a route to serve a webpage template based on the assigned template type using the EJS template engine. An object `templateData` is created with the `templateType` parameter. The EJS `render` method is used to generate the HTML output based on the `templateType` parameter and the `templateData` object. The HTML output is then sent as the response.

Note that for this to work, you'll need to create separate EJS templates for each template type (e.g. `template1.ejs`, `template2.ejs`, etc.) in a `views` directory. Alternatively, you can use another template engine, such as Handlebars, or serve HTML files directly without a template engine.
